import { useEffect, useState } from "react";
import { Link } from "react-router-dom";

export default function Dashboard() {
  const [incidents, setIncidents] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState("ALL");
  const [search, setSearch] = useState("");

  const fetchData = async () => {
    try {
      setLoading(true);
      const res = await fetch("http://localhost:8000/incidents");
      const data = await res.json();
      setIncidents(data);
    } catch {
      alert("Failed to fetch");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 5000);
    return () => clearInterval(interval);
  }, []);

  // FILTER + SEARCH
  const filtered = incidents
    .filter(i => filter === "ALL" || i.status === filter)
    .filter(i => i.component_id.toLowerCase().includes(search.toLowerCase()))
    .sort((a, b) => b.id - a.id);

  // KPIs
  const total = incidents.length;
  const open = incidents.filter(i => i.status === "OPEN").length;
  const closed = incidents.filter(i => i.status === "CLOSED").length;

  return (
    <div style={{ padding: "20px", fontFamily: "Segoe UI" }}>
      
      {/* HEADER */}
      <h1 style={{ textAlign: "center" }}>🚨 Incident Dashboard</h1>

      {/* KPI CARDS */}
      <div style={kpiContainer}>
        <KPI title="Total" value={total} color="#007bff" />
        <KPI title="Open" value={open} color="red" />
        <KPI title="Closed" value={closed} color="green" />
      </div>

      {/* CONTROLS */}
      <div style={{ textAlign: "center", marginBottom: "15px" }}>
        <input
          placeholder="Search component..."
          onChange={(e) => setSearch(e.target.value)}
          style={input}
        />

        <button onClick={() => setFilter("ALL")}>All</button>
        <button onClick={() => setFilter("OPEN")}>Open</button>
        <button onClick={() => setFilter("CLOSED")}>Closed</button>
      </div>

      {loading && <p style={{ textAlign: "center" }}>Loading...</p>}

      <div style={grid}>
        {filtered.map((i) => (
          <div key={i.id} style={card}>
            <h3>Incident #{i.id}</h3>

            <p><b>{i.component_id}</b></p>
            <p>Severity: {i.severity}</p>

            <p style={{ color: i.status === "OPEN" ? "red" : "green" }}>
              {i.status}
            </p>

            <p>Signals: {i.signal_count}</p>

            <Link to={`/incident/${i.id}`}>
              <button>View Details</button>
            </Link>
          </div>
        ))}
      </div>
    </div>
  );
}

// KPI CARD
function KPI({ title, value, color }) {
  return (
    <div style={{ ...kpi, borderTop: `4px solid ${color}` }}>
      <h4>{title}</h4>
      <h2>{value}</h2>
    </div>
  );
}

// STYLES
const grid = {
  display: "grid",
  gridTemplateColumns: "repeat(auto-fit, minmax(250px, 1fr))",
  gap: "15px"
};

const card = {
  padding: "15px",
  background: "#fff",
  borderRadius: "10px",
  boxShadow: "0 2px 8px rgba(0,0,0,0.1)"
};

const kpiContainer = {
  display: "flex",
  justifyContent: "center",
  gap: "20px",
  marginBottom: "20px"
};

const kpi = {
  padding: "10px",
  background: "#fff",
  borderRadius: "8px",
  width: "120px",
  textAlign: "center",
  boxShadow: "0 2px 6px rgba(0,0,0,0.1)"
};

const input = {
  padding: "6px",
  marginRight: "10px",
  borderRadius: "5px",
  border: "1px solid #ccc"
};
